mapper.select:
		/*
			 토론 게시글 수 카운팅
			 ForumAtclDAO.forumAtclCount
		*/
        SELECT COUNT(*)
        FROM TB_LMS_DSCS_ATCL
        WHERE DSCS_ID = #{forumCd}
          AND RGTR_ID = #{rgtrId}
          AND DELYN = 'N'

/* 토론 게시글의 검색된 수를 카운팅 ForumAtclDAO.count */ SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL A LEFT JOIN TB_LMS_USER U ON U.USER_ID = A.RGTR_ID WHERE A.DSCS_ID = #{forumCd} AND (A.DELYN = 'N' OR EXISTS ( SELECT 1 FROM TB_LMS_DSCS_CMNT C WHERE C.DSCS_ATCL_ID = A.DSCS_ATCL_ID AND C.DELYN = 'N' ))
AND ( LOWER(A.RGTR_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(U.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.USER_ID IN
#{item}

mapper.insert:
		/*
			 토론글 등록
			 ForumAtclVO.insertAtcl
		*/
        INSERT INTO TB_LMS_DSCS_ATCL (
              DSCS_ATCL_ID
            , DSCS_ID
            , USER_ID
            , UP_DSCS_ATCL_ID
            , ATCL_LV
            , ATCL_SEQNO
            , DSCS_ATCL_TYCD
            , OKNOK_GBNCD
            , ATCL_TTL
            , ATCL_CTS
            , ATCL_CTS_LEN
            , INQ_CNT
            , EDTR_USEYN
            , DELYN
            , RGTR_ID
            , REG_DTTM
            , MDFR_ID
            , MOD_DTTM
        ) VALUES (
              #{atclSn}
            , #{forumCd}
            , #{userId}
            , #{parAtclSn}
            , 0
            , #{atclOdr}
            , #{atclTypeCd}
            , #{prosConsTypeCd}
            , #{title}
            , #{cts}
            , #{ctsLen}
            , 0
            , 'N'
            , 'N'
            , #{userId}
            , FN_DTTM()
            , #{userId}
            , FN_DTTM()
        )

mapper.update:
		/*
			 토론 게시글 수정
			 ForumAtclDAO.updateAtcl
		*/
        UPDATE TB_LMS_DSCS_ATCL
        SET MDFR_ID = #{mdfrId}
          , MOD_DTTM = FN_DTTM()

          , UP_DSCS_ATCL_ID = #{parAtclSn}


          , ATCL_LV = #{atclLvl}


          , ATCL_SEQNO = #{atclOdr}


          , DSCS_ATCL_TYCD = #{atclTypeCd}


          , OKNOK_GBNCD = #{prosConsTypeCd}


          , ATCL_TTL = #{title}


          , ATCL_CTS = #{cts}
          , ATCL_CTS_LEN = #{ctsLen}


          , INQ_CNT = #{hits}


          , EDTR_USEYN = #{editorYn}


          , DELYN = #{delYn}

        WHERE DSCS_ATCL_ID = #{atclSn}
          AND DSCS_ID = #{forumCd}

		/*
			 토론 게시글 삭제
			 ForumAtclDAO.deleteAtcl
		*/
        UPDATE TB_LMS_DSCS_ATCL
        SET DELYN = 'Y'
          , MDFR_ID = #{mdfrId}
          , MOD_DTTM = FN_DTTM()
        WHERE DSCS_ATCL_ID = #{atclSn}
          AND DSCS_ID = #{forumCd}
